import (
	"errors"
	"fmt"
)

var ErrNotFound = errors.New("not found")
var ErrUnauthorized = errors.New("unauthorized")

func getUser(id int) (string, error) {
	if id == 0 {
		return "", ErrNotFound
	}
	if id < 0 {
		return "", ErrUnauthorized
	}
	return "Alex", nil
}

func main() {
	ids := []int{1, 0, -1}
	for _, id := range ids {
		name, err := getUser(id)
		if err == nil {
			fmt.Println("Found:", name)
		} else if errors.Is(err, ErrNotFound) {
			fmt.Println("User not found")
			// TODO: add check for ErrUnauthorized
		} else {
			fmt.Println("Unknown error:", err)
		}
	}
}

package main

import (
	"errors"
	"fmt"
)

type ValidationError struct {
	Field   string
	Message string
}

func (e ValidationError) Error() string {
	return fmt.Sprintf("%s: %s", e.Field, e.Message)
}

func validateAge(age int) error {
	if age < 0 || age > 120 {
		return ValidationError{Field: "age", Message: fmt.Sprintf("%d is out of range", age)}
	}
	return nil
}

func main() {
	err := validateAge(200)
	if err != nil {
		fmt.Println("Error:", err)

		var ve ValidationError
		if errors.As(err, &ve) {
			fmt.Println("Problem field:", ve.Field)
			fmt.Println("Details:", ve.Message)
		}
	}
}

